def safe_divide(a, b):
    try:
        result = a / b
        return result
    except ZeroDivisionError:
        print('오류: 0으로 나눌 수 없습니다')
        return None
    except TypeError:
        print('오류: 숫자만 입력하세요')
        return None

print(safe_divide(10, 2))   # 5.0
print(safe_divide(10, 0))   # 오류 메시지 + None
print(safe_divide(10, '2')) # 오류 메시지 + None

def open_and_read(filename):
    try:
        f = open(filename, 'r')
        content = f.read()
    except FileNotFoundError:
        print(f'파일을 찾을 수 없습니다: {filename}')
    else:
        print(f'파일 읽기 성공: {len(content)}글자')
        f.close()
    finally:
        print('파일 작업 완료')

open_and_read('없는파일.txt')

def check_score(score):
    if score < 0 or score > 100:
        raise ValueError(f'점수는 0~100 사이여야 합니다. 입력값: {score}')
    return score

try:
    check_score(150)
except ValueError as e:
    print(f'오류: {e}')

try:
    result = check_score(85)
    print(f'점수: {result}점')
except ValueError as e:
    print(f'오류: {e}')
